Create Account.code:
// Create an Account record in Dynamics.
createEntity({
  // Plural-cased Dataverse entity set.
  entityName: 'accounts',
  body: {
    name: $.data.name,
    emailaddress1: $.data.email,
    telephone1: $.data.phone,
  },
});

Create Case/Incident.code:
// Create a Case (incident) record.
createEntity({
  entityName: 'incidents',
  body: {
    title: $.data.title,
    description: $.data.description,
    // Lookup back to the parent account using an @odata.bind reference.
    'customerid_account@odata.bind': `/accounts(${$.data.accountId})`,
  },
});

Create Contact.code:
// Create a Contact record.
createEntity({
  entityName: 'contacts',
  body: {
    firstname: $.data.firstName,
    lastname:  $.data.lastName,
    emailaddress1: $.data.email,
  },
});

Create Custom Entity.code:
// Create a record in a custom entity. Use the entity's plural set name.
createEntity({
  entityName: 'my_custom_entities',
  body: $.data.record,
});

Create Invoice.code:
// Create an Invoice.
createEntity({
  entityName: 'invoices',
  body: {
    name: $.data.invoiceName,
    'customerid_account@odata.bind': `/accounts(${$.data.accountId})`,
    totalamount: $.data.total,
  },
});

