Update Account.code:
// Update fields on an existing Account.
updateEntity({
  entityName: 'accounts',
  // The record's GUID.
  entityId: $.data.accountId,
  body: {
    telephone1: $.data.phone,
    emailaddress1: $.data.email,
  },
});

