  },
});

Update Record.code:
// Update a record on any entity, by GUID.
updateEntity({
  entityName: $.data.entityName,
  entityId:   $.data.recordId,
  body:       $.data.fields,
});

Find Account.code:
// Look up Accounts by name using an OData filter.
query({
  entityName: 'accounts',
  // OData $filter; quote string values with single quotes.
  filter: `name eq '${$.data.name}'`,
  // Only return the columns we care about.
  select: ['accountid', 'name', 'emailaddress1'],
});

Find Campaign Response.code:
// Look up Campaign Responses.
query({
  entityName: 'campaignresponses',
  filter: `_regardingobjectid_value eq ${$.data.campaignId}`,
});

Find Contact.code:
// Look up a Contact by email.
query({
  entityName: 'contacts',
  filter: `emailaddress1 eq '${$.data.email}'`,
  select: ['contactid', 'firstname', 'lastname', 'emailaddress1'],
});

Find Custom Entity.code:
// Look up records on a custom entity.
query({
  entityName: 'my_custom_entities',
  filter: `my_externalid eq '${$.data.externalId}'`,
});

